import { ERR, raise, report, step, statsOf } from './errors.js';
import L from 'leaflet';
let _gtP; const getGeotiff = () => _gtP ||= import('geotiff');
let _p4P; const getProj4   = () => _p4P ||= import('proj4').then(m => m.default || m);

// 返り値：{ ok:true, layer, bounds, revoke } または { ok:false, reason:'NEED_CRS', suggestion?: '4326'|'3857' }
export async function loadGeoTiffAsOverlay(buf, { signal, forcedCrs = null, worldFile = null } = {}) {
  if (signal?.aborted) throw new DOMException('Aborted','AbortError');
  const { fromArrayBuffer } = await getGeotiff();
  const tiff = await fromArrayBuffer(buf);
  if (signal?.aborted) throw new DOMException('Aborted','AbortError');
  const img = await tiff.getImage();
  if (signal?.aborted) throw new DOMException('Aborted','AbortError');

  // Blob URL 作成
  const raster = await img.readRasters({ interleave: true, pool: null });
  if (signal?.aborted) throw new DOMException('Aborted','AbortError');
  const w = img.getWidth(), h = img.getHeight();
  const canvas = document.createElement('canvas');
  canvas.width = w; canvas.height = h;
  const ctx = canvas.getContext('2d');
  const imageData = new ImageData(w, h);
  // RGBA 想定：足りなければアルファ255で埋める
  if (raster.length === w * h * 4) {
    imageData.data.set(raster);
  } else if (raster.length === w * h * 3) {
    const d = imageData.data;
    for (let i=0,j=0; i<raster.length; i+=3, j+=4) {
      d[j]=raster[i]; d[j+1]=raster[i+1]; d[j+2]=raster[i+2]; d[j+3]=255;
    }
  } else {
    // 単バンドなどは簡易グレイスケール
    const d = imageData.data;
    for (let i=0,j=0; i<w*h; i++, j+=4) {
      const v = raster[i] ?? 0;
      d[j]=v; d[j+1]=v; d[j+2]=v; d[j+3]=255;
    }
  }
  ctx.putImageData(imageData, 0, 0);
  const blob = await new Promise(r => canvas.toBlob(r, 'image/png'));
  const url = URL.createObjectURL(blob);
  const revoke = () => URL.revokeObjectURL(url);

  // 1) bbox を取得できるか試す
  let bbox = null;
  try { bbox = img.getBoundingBox(); } catch {}

  // 2) CRS 判定／強制
  let crs = forcedCrs; // 'EPSG:4326' | 'EPSG:3857' | null
  if (!crs) {
    if (bbox) {
      const [minX,minY,maxX,maxY] = bbox;
      const inLonLat = Math.max(Math.abs(minX),Math.abs(maxX)) <= 180 && Math.max(Math.abs(minY),Math.abs(maxY)) <= 90;
      const inMerc   = Math.max(Math.abs(minX),Math.abs(maxX)) > 180 && Math.max(Math.abs(minY),Math.abs(maxY)) > 90 &&
                       Math.max(Math.abs(minX),Math.abs(maxX)) <= 20040000 && Math.max(Math.abs(minY),Math.abs(maxY)) <= 20040000;
      if (inLonLat) crs = 'EPSG:4326';
      else if (inMerc) crs = 'EPSG:3857';
    }
  }

  // 3) bbox が無い場合は WorldFile から推定（回転0前提: B=D=0）
  if (!bbox && worldFile) {
    const tfw = parseTfw(worldFile);
    if (tfw && Math.abs(tfw.B) < 1e-9 && Math.abs(tfw.D) < 1e-9) {
      // A: pixel size X、E: -pixel size Y、C,F: 左上座標
      const minX = tfw.C;
      const maxY = tfw.F;
      const maxX = minX + tfw.A * w;
      const minY = maxY + tfw.E * h; // E は負数想定
      bbox = [minX, minY, maxX, maxY];
      // TFWに対しても CRS 必須
      crs = crs || 'EPSG:4326'; // デフォルトは WGS84 とみなす（UIで 3857 を選べば forcedCrs で上書き）
    }
  }

  if (!bbox || !crs) {
    revoke();
    return { ok:false, reason:'NEED_CRS', suggestion: bbox ? '3857' : undefined };
  }

  // 4) Leaflet bounds（必ず 4326 に正規化）
  let latlngBounds;
  if (crs === 'EPSG:4326') {
    const [minX,minY,maxX,maxY] = bbox;
    latlngBounds = L.latLngBounds([minY,minX],[maxY,maxX]);
  } else if (crs === 'EPSG:3857') {
    const [minX,minY,maxX,maxY] = bbox;
    const proj4 = await getProj4();
    const sw = proj4('EPSG:3857','EPSG:4326',[minX,minY]);
    const ne = proj4('EPSG:3857','EPSG:4326',[maxX,maxY]);
    latlngBounds = L.latLngBounds([sw[1],sw[0]],[ne[1],ne[0]]);
  } else {
    revoke();
    return { ok:false, reason:`CRS ${crs} is not supported in P1` };
  }

  const layer = L.imageOverlay(url, latlngBounds, { opacity: 0.9, pane: 'overlayPane' });
  return { ok:true, layer, bounds: latlngBounds, revoke };
}

function parseTfw(text) {
  try {
    const lines = (text || '').trim().split(/\r?\n/).map(s => parseFloat(s.trim()));
    if (lines.length < 6 || lines.some(n => Number.isNaN(n))) return null;
    const [A, D, B, E, C, F] = lines; // 6行の順序に注意（業界慣習）
    return { A, D, B, E, C, F };
  } catch {
    return null;
  }
}

// ✅ hoistedな関数宣言にして、minify後も"定義前参照"を回避
function normalizeBand(arr){
  let min = Infinity, max = -Infinity;
  for (let i = 0; i < arr.length; i++){
    const v = arr[i];
    if (Number.isFinite(v)){ if (v < min) min = v; if (v > max) max = v; }
  }
  if (!Number.isFinite(min) || !Number.isFinite(max) || min === max){ min = 0; max = 1; }
  const denom = (max - min) || 1;
  return function(v){
    if (!Number.isFinite(v)) return 0;
    const n = ((v - min) / denom) * 255;
    return n < 0 ? 0 : n > 255 ? 255 : n;
  };
}

/**
 * v1/v2両対応で最も粗いオーバービュー（軽量表示）を取得
 * @param {Object} image - GeoTIFFイメージ
 * @returns {Promise<Object>} オーバービューまたは元のイメージ
 */
async function pickCoarsestOverview(image){
  if (typeof image.getOverviews === 'function'){               // v2
    const ovs = await image.getOverviews();
    return (ovs && ovs.length) ? ovs[ovs.length - 1] : image;
  }
  if (typeof image.getOverviewCount === 'function'             // v1
   && typeof image.getOverview === 'function'){
    const n = image.getOverviewCount();
    return (n && n > 0) ? image.getOverview(n - 1) : image;
  }
  return image;
}

/**
 * RGBA → Blob URL 生成
 * options:
 *  - useOverview: true なら最も低解像度オーバービューで描画（高速プレビュー）
 *  - previewMaxPixels: しきい値（例: 1e6）を超える場合はオーバービューを選択
 *  - window: [xmin, ymin, xmax, ymax] ピクセル座標で部分読み出し（COG前提で高速）
 */
export async function rgbaToBlobUrl(image, options = {}) {
  const { useOverview = false, previewMaxPixels = 1_000_000, window = null } = options;
  let img = image;
  try {
    const W = image.getWidth(), H = image.getHeight();
    const hasOv = typeof image.getOverviews === 'function' && image.getOverviews().length > 0;
    if ((useOverview || W * H > previewMaxPixels) && hasOv) {
      const ovs = image.getOverviews();
      img = ovs[ovs.length - 1]; // 最も低解像度
      report({ phase: 'overview-picked', size: [img.getWidth(), img.getHeight()] }, 'info');
    }
  } catch {}

  // readRasters の窓読み（COGなら速い）
  const readOpts = { interleave: true };
  if (window && Array.isArray(window) && window.length === 4) readOpts.window = window;

  const data = await step('geotiff.readRasters', () => img.readRasters(readOpts));
  const width = img.getWidth(), height = img.getHeight();

  // ===== ここから：どのチャンネル数でも RGBA に組み立てる =====
  const samples = (img.getSamplesPerPixel?.() ?? img.fileDirectory?.SamplesPerPixel ?? 1);
  const bits    = (img.getBitsPerSample?.() ?? img.fileDirectory?.BitsPerSample ?? [8]);
  const isByte  = Array.isArray(bits) ? bits.every(b => b === 8) : bits === 8;

  // data は interleave:true のため、長さは width*height*samples
  const src = data; // TypedArray
  const N   = width * height;
  // 8bit 以外（UInt16/Float等）の場合は 0..255 に正規化
  const needNormalize = !isByte || !(src instanceof Uint8Array || src instanceof Uint8ClampedArray);

  // 簡易正規化（各チャンネルごとに min-max スケーリング）
  function normalizeChannel(chanIndex) {
    if (!needNormalize) return { min: 0, max: 255 };
    let min = Infinity, max = -Infinity;
    for (let i = chanIndex; i < src.length; i += samples) {
      const v = src[i];
      if (v < min) min = v;
      if (v > max) max = v;
    }
    if (min === max) { // 定数面は白で
      min = 0; max = 1;
    }
    return { min, max };
  }
  const chStats = Array.from({ length: samples }, (_, c) => normalizeChannel(c));

  const out = new Uint8ClampedArray(N * 4);
  // サンプル数に応じた合成
  if (samples === 4) {
    // 想定：RGBA（あるいはRGB+Alpha）。順番そのまま入れる
    for (let p = 0, si = 0; p < N; p++, si += 4) {
      for (let c = 0; c < 4; c++) {
        const { min, max } = chStats[c];
        const v = src[si + c];
        out[p * 4 + c] = needNormalize ? ((v - min) * 255) / (max - min) : v;
      }
    }
  } else if (samples === 3) {
    // RGB → RGBA（A=255）
    const s0 = chStats[0], s1 = chStats[1], s2 = chStats[2];
    for (let p = 0, si = 0; p < N; p++, si += 3) {
      out[p*4]   = needNormalize ? ((src[si]   - s0.min) * 255) / (s0.max - s0.min) : src[si];
      out[p*4+1] = needNormalize ? ((src[si+1] - s1.min) * 255) / (s1.max - s1.min) : src[si+1];
      out[p*4+2] = needNormalize ? ((src[si+2] - s2.min) * 255) / (s2.max - s2.min) : src[si+2];
      out[p*4+3] = 255;
    }
  } else if (samples === 2) {
    // 想定：Gray + Alpha
    const s0 = chStats[0], s1 = chStats[1];
    for (let p = 0, si = 0; p < N; p++, si += 2) {
      const g = needNormalize ? ((src[si] - s0.min) * 255) / (s0.max - s0.min) : src[si];
      const a = needNormalize ? ((src[si+1] - s1.min) * 255) / (s1.max - s1.min) : src[si+1];
      out[p*4] = out[p*4+1] = out[p*4+2] = g;
      out[p*4+3] = a;
    }
  } else if (samples === 1) {
    // Gray → RGBA（A=255）
    const s0 = chStats[0];
    for (let p = 0; p < N; p++) {
      const v = needNormalize ? ((src[p] - s0.min) * 255) / (s0.max - s0.min) : src[p];
      out[p*4] = out[p*4+1] = out[p*4+2] = v;
      out[p*4+3] = 255;
    }
  } else {
    // 非想定（5バンド以上など）は最初の3つをRGB、A=255にする
    const s0 = chStats[0] ?? {min:0,max:255};
    const s1 = chStats[1] ?? s0;
    const s2 = chStats[2] ?? s1;
    for (let p = 0, si = 0; p < N; p++, si += samples) {
      out[p*4]   = needNormalize ? ((src[si]   - s0.min) * 255) / (s0.max - s0.min) : src[si];
      out[p*4+1] = needNormalize ? ((src[si+1] - s1.min) * 255) / (s1.max - s1.min) : src[si+1];
      out[p*4+2] = needNormalize ? ((src[si+2] - s2.min) * 255) / (s2.max - s2.min) : src[si+2];
      out[p*4+3] = 255;
    }
  }
  // ===== ここまで：RGBA 組み立て =====

  // Canvas → Blob → URL
  const canvas = document.createElement('canvas');
  canvas.width = width; canvas.height = height;
  const ctx = canvas.getContext('2d', { willReadFrequently: false });
  const imageData = new ImageData(out, width, height);
  ctx.putImageData(imageData, 0, 0);
  const blob = await new Promise(res => canvas.toBlob(res, 'image/png'));
  return URL.createObjectURL(blob);
}

// 互換エクスポート
export const makeRgbaBlobUrl = rgbaToBlobUrl;
export default rgbaToBlobUrl;

/**
 * ファイルを読み込む関数
 * @param {File} file - 読み込むファイル
 * @returns {Promise<Object>} ファイルデータ
 */
export async function loadFile(file) {
  const fileExtension = file.name.split('.').pop().toLowerCase();
  
  switch (fileExtension) {
    case 'tif':
    case 'tiff':
    case 'geotiff':
      return await loadGeoTIFF(file);
    case 'gpkg':
      return await loadGeoPackage(file);
    case 'shp':
      return await loadShapefile(file);
    default:
      throw new Error(`サポートされていないファイル形式: ${fileExtension}`);
  }
}

/**
 * GeoTIFF/COGファイルを読み込む関数
 * @param {File} file - 読み込むGeoTIFFファイル
 * @returns {Promise<Object>} GeoTIFFイメージデータ
 */
export async function loadGeoTIFF(input) {
  try {
    // 1) ArrayBuffer 化
    const arrayBuffer = await step('read.arrayBuffer', async () => {
      if (input instanceof ArrayBuffer) return input;
      if (input instanceof Blob) return await input.arrayBuffer();
      if (input?.buffer instanceof ArrayBuffer) return input.buffer;
      throw raise(ERR.GEO_OPEN, 'サポートされない入力型です', { type: Object.prototype.toString.call(input) });
    });
    console.info('buffer bytes:', arrayBuffer.byteLength.toLocaleString());

    // 2) GeoTIFF パース
    const tiff = await step('geotiff.fromArrayBuffer', async () => {
      try { return await fromArrayBuffer(arrayBuffer); }
      catch (e) { throw raise(ERR.GEO_PARSE, 'geotiff.fromArrayBuffer() に失敗', { size: arrayBuffer.byteLength }, e); }
    });

    // 3) 画像選択（getImage / getOverviews）
    const base = await step('geotiff.getImage', async () => {
      try { return await tiff.getImage(); }
      catch (e) { throw raise(ERR.GEO_GET_IMAGE, 'getImage() に失敗', {}, e); }
    });
    const info = {
      width: base.getWidth?.(),
      height: base.getHeight?.(),
      bbox: base.getBoundingBox?.(),
      srs: base.getGeoKeys?.(),
      samples: base.getSamplesPerPixel?.(),
      bits: base.getBitsPerSample?.(),
      planar: base.getPlanarConfiguration?.(),
      hasOverviews: typeof base.getOverviews === 'function',
    };
    console.groupCollapsed('ℹ️ GeoTIFF image info'); console.table(info); console.groupEnd();

    const image = await step('geotiff.pickOverview', async () => {
      try {
        if (typeof base.getOverviews === 'function') {
          const ovs = await base.getOverviews();
          console.info('overview count:', ovs?.length || 0);
          if (ovs && ovs.length) return ovs[0];
        }
        return base;
      } catch (e) {
        throw raise(ERR.GEO_PICK_OV, 'オーバービュー取得に失敗', {}, e);
      }
    });

    // 4) ピクセル読取
    const rasters = await step('geotiff.readRasters', async () => {
      try {
        return await image.readRasters({ interleave: false });
      } catch (e) {
        throw raise(ERR.GEO_RASTERS, 'readRasters() に失敗', {
          width: image.getWidth?.(), height: image.getHeight?.(),
          samples: image.getSamplesPerPixel?.(),
        }, e);
      }
    });
    // 代表統計
    const summary = Array.from(rasters).slice(0, 3).map((r, i) => ({ band: i, ...statsOf(r) }));
    console.groupCollapsed('📈 raster stats (first 3 bands)'); console.table(summary); console.groupEnd();

    // 5) RGBA 化 → BlobURL
    const { url, bounds } = await step('render.rgbaToBlobUrl', async () => {
      return await rgbaToBlobUrl(image, rasters);
    });

    return { url, bounds };
  } catch (e) {
    report(e);
    throw e; // 呼び出し側にも伝播
  }
}

/**
 * GeoTIFF/COGファイルをArrayBufferから読み込む関数
 * @param {ArrayBuffer} arrayBuffer - GeoTIFFデータのArrayBuffer
 * @returns {Promise<Object>} GeoTIFFイメージデータ
 */
export async function loadGeoTIFFFromArrayBuffer(arrayBuffer) {
  try {
    // GeoTIFFとして解析
    const tiff = await fromArrayBuffer(arrayBuffer);
    
    // 画像のメタデータを取得
    const image = await tiff.getImage();
    const metadata = image.getFileDirectory();
    const geoKeys = image.getGeoKeys();
    
    // 画像データを取得
    // 既定はフル解像度の一枚目
    // 軽量表示：最も粗いオーバービューを使う（v1/v2両対応）
    const targetImage = await pickCoarsestOverview(image);
    
    // 大きな画像の場合はダウンサンプリング
    const readOpts = { interleave: false };
    if (targetImage === image && typeof image.getWidth === 'function') {
      const w = image.getWidth(), h = image.getHeight();
      const max = 4096;
      if (Math.max(w, h) > max) {
        if (w >= h) {
          readOpts.width = max;
        } else {
          readOpts.height = max;
        }
      }
    }
    const imageData = await targetImage.readRasters(readOpts);
    
    // RGBA化処理
    const { dataUrl, boundsLatLng } = await createRGBAImageFromGeoTIFF(imageData, image, targetImage.getWidth(), targetImage.getHeight());
    
    // オーバービュー情報を取得
    let overviews = [];
    try {
      if (typeof image.getOverviews === 'function') {
        const ovs = await image.getOverviews(); // v2
        overviews = ovs.map(ov => ({
          width: ov.getWidth(),
          height: ov.getHeight(),
          scale: image.getWidth() / ov.getWidth()
        }));
      } else if (typeof image.getOverviewCount === 'function' && typeof image.getOverview === 'function') {
        const overviewCount = image.getOverviewCount(); // v1
        for (let i = 0; i < overviewCount; i++) {
          const overview = await image.getOverview(i);
          overviews.push({
            width: overview.getWidth(),
            height: overview.getHeight(),
            scale: image.getWidth() / overview.getWidth()
          });
        }
      }
    } catch (error) {
      console.warn('オーバービュー情報の取得に失敗しました:', error);
      overviews = [];
    }
    
    return {
      type: 'geotiff',
      tiff,
      image,
      metadata,
      geoKeys,
      imageData,
      width: targetImage.getWidth(),
      height: targetImage.getHeight(),
      bbox: targetImage.getBoundingBox(),
      boundsLatLng, // 追加
      overviews,
      isCog: overviews.length > 0,
      dataUrl // 追加
    };
  } catch (error) {
    console.error('GeoTIFFの読み込みエラー:', error);
    throw error;
  }
}

