/**
 * COGの特定の範囲を読み込む関数
 * @param {GeoTIFF} tiff - GeoTIFFオブジェクト
 * @param {Object} options - 読み込みオプション
 * @returns {Promise<Object>} 画像データ
 */
export async function loadCOGRange(tiff, options = {}) {
  try {
    const image = await tiff.getImage(options);
    const imageData = await image.readRasters(options);
    
    return {
      image,
      imageData,
      width: image.getWidth(),
      height: image.getHeight(),
      bbox: image.getBoundingBox()
    };
  } catch (error) {
    console.error('COG範囲読み込みエラー:', error);
    throw error;
  }
}

/**
 * 解像度に基づいて適切なオーバービューを選択
 * @param {Array} overviews - オーバービュー情報の配列
 * @param {number} resolution - 要求解像度
 * @returns {Object|null} 適切なオーバービュー情報
 */
export function selectOverviewByResolution(overviews, resolution) {
  if (!overviews || overviews.length === 0) return null;
  
  // 要求解像度に最も近いオーバービューを選択
  let selectedOverview = overviews[0];
  let minDiff = Math.abs(resolution - selectedOverview.scale);
  
  for (let i = 1; i < overviews.length; i++) {
    const diff = Math.abs(resolution - overviews[i].scale);
    if (diff < minDiff) {
      minDiff = diff;
      selectedOverview = overviews[i];
    }
  }
  
  return selectedOverview;
}

/**
 * GeoTIFFデータからキャンバスイメージを作成
 * @param {Object} geoTiffData - GeoTIFFデータ
 * @returns {HTMLCanvasElement} キャンバス要素
 */
export async function createCanvasFromGeoTIFF(geoTiffData) {
  const { width, height, imageData, image } = geoTiffData;
 
  // キャンバスを作成
  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d');
 
  // 画像データをキャンバスに描画（RGB または グレースケール）
  if (imageData && imageData.length) {
    // グレースケール（1バンド）の場合
    if (imageData.length === 1) {
      const band = imageData[0];
      const out = ctx.createImageData(width, height);
      
      // NoData 値の取得と処理
      const nodataRaw = image.getGDALNoData ? await image.getGDALNoData() : undefined;
      const nodata = nodataRaw !== undefined && nodataRaw !== null && nodataRaw !== '' ? Number(nodataRaw) : undefined;
      const norm = normalizeBand(band);
      
      for (let i=0;i<band.length;i++){
        const v = band[i];
        const p = i<<2;
        if (nodata !== undefined && Number.isFinite(nodata) && v === nodata){
          out.data[p+3] = 0;              // NoData は完全に透明
          continue;
        }
        const g = norm(v)|0;
        out.data[p] = out.data[p+1] = out.data[p+2] = g;
        out.data[p+3] = 255;              // 可視化する画素は不透明
      }
      ctx.putImageData(out, 0, 0);
    } else {
      // RGB(A)（3〜4バンド）の場合
      const R=imageData[0], G=imageData[1], B=imageData[2], A=imageData[3];
      const hasAlpha = imageData.length===4;
      const nodataRaw = image.getGDALNoData ? await image.getGDALNoData() : undefined;
      const nodata = nodataRaw !== undefined && nodataRaw !== null && nodataRaw !== '' ? Number(nodataRaw) : undefined;
      const len = R.length;
      const out = ctx.createImageData(width, height);
      
      for (let i=0;i<len;i++){
        const p=i<<2;
        if (nodata !== undefined && Number.isFinite(nodata) && (R[i]===nodata || G[i]===nodata || B[i]===nodata)){
          out.data[p+3]=0;               // NoData は透明
          continue;
        }
        out.data[p]=R[i]; out.data[p+1]=G[i]; out.data[p+2]=B[i];
        out.data[p+3]=hasAlpha ? A[i] : 255; // 不透明で重ねる
      }
      ctx.putImageData(out, 0, 0);
    }
  } else {
    // デフォルトの表示（テスト用）
    ctx.fillStyle = '#8bc34a';
    ctx.fillRect(0, 0, width, height);
  }
 
  return canvas;
}

function detectProj4Def(image){
  const gk = image.getGeoKeys ? image.getGeoKeys() : {};
  const pcs = gk?.ProjectedCSTypeGeoKey;      // 例: 32654 = UTM zone 54N (WGS84)
  const gcs = gk?.GeographicTypeGeoKey;       // 4326 / 4612(JGD2000) / 6668(JGD2011) など
  const cit = gk?.PCSCitationGeoKey || gk?.GeogCitationGeoKey || '';
  // 経緯度系（WGS84/JGD）は 4326 相当として扱う（数m差は実務上許容）
  if (gcs === 4326 || gcs === 4612 || gcs === 6668) return 'EPSG:4326';
  if (pcs === 4326) return 'EPSG:4326';
  // UTM (WGS84) の典型
  if (pcs >= 32601 && pcs <= 32660){ const zone = pcs - 32600; return `+proj=utm +zone=${zone} +datum=WGS84 +units=m +no_defs`; }
  if (pcs >= 32701 && pcs <= 32760){ const zone = pcs - 32700; return `+proj=utm +zone=${zone} +south +datum=WGS84 +units=m +no_defs`; }
  // 引用文字列から "zone 54N" のような表記を拾う
  const m = /zone\s*(\d+)\s*([NS])?/i.exec(String(cit));
  if (m){ const zone=Number(m[1]); const south=(m[2]||'N').toUpperCase()==='S'; return `+proj=utm +zone=${zone}${south?' +south':''} +datum=WGS84 +units=m +no_defs`; }
  // 不明なら経緯度とみなす（最小驚き：少なくとも表示はされる）
  return 'EPSG:4326';
}

async function bboxToLeafletBounds4326(bbox, srcProjDef){
  // bbox: [minX,minY,maxX,maxY]（画像の座標系）
  const proj4 = await getProj4();
  const toWGS84 = (xy) => srcProjDef==='EPSG:4326' ? [xy[1], xy[0]] : proj4(srcProjDef, 'EPSG:4326', xy).slice().reverse();
  const p1 = toWGS84([bbox[0], bbox[1]]); // SW?
  const p2 = toWGS84([bbox[2], bbox[3]]); // NE?
  // 投影→緯度経度へ変換後、Leaflet 用に [ [南,西], [北,東] ] を正規化
  const south = Math.min(p1[0], p2[0]), north = Math.max(p1[0], p2[0]);
  const west  = Math.min(p1[1], p2[1]), east  = Math.max(p1[1], p2[1]);
  return [[south, west], [north, east]];
}

/**
 * GeoTIFFデータからキャンバスイメージを作成（RGBA化 & バウンディングボックス変換）
 * @param {Object} imageData - 画像データ
 * @param {Object} image - GeoTIFFイメージ
 * @param {number} width - 画像の幅
 * @param {number} height - 画像の高さ
 * @returns {Object} dataUrlとboundsLatLngを含むオブジェクト
 */
async function createRGBAImageFromGeoTIFF(imageData, image, width, height) {
  // キャンバスを作成
  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d');
  
  // 画像データをキャンバスに描画（RGB または グレースケール）
  if (imageData && imageData.length) {
    // グレースケール（1バンド）の場合
    if (imageData.length === 1) {
      const band = imageData[0];
      const out = ctx.createImageData(width, height);
      
      // NoData 値の取得と処理
      const nodataRaw = image.getGDALNoData ? await image.getGDALNoData() : undefined;
      const nodata = nodataRaw !== undefined && nodataRaw !== null && nodataRaw !== '' ? Number(nodataRaw) : undefined;
      const norm = normalizeBand(band);
      
      for (let i=0;i<band.length;i++){
        const v = band[i];
        const p = i<<2;
        if (nodata !== undefined && Number.isFinite(nodata) && v === nodata){
          out.data[p+3] = 0;              // NoData は完全に透明
          continue;
        }
        const g = norm(v)|0;
        out.data[p] = out.data[p+1] = out.data[p+2] = g;
        out.data[p+3] = 255;              // 可視化する画素は不透明
      }
      ctx.putImageData(out, 0, 0);
    } else {
      // RGB(A)（3〜4バンド）の場合
      const R=imageData[0], G=imageData[1], B=imageData[2]; // 4番目はアルファ扱いしない（NIR等の可能性）
      const nodataRaw = image.getGDALNoData ? await image.getGDALNoData() : undefined;
      const nodata = nodataRaw !== undefined && nodataRaw !== null && nodataRaw !== '' ? Number(nodataRaw) : undefined;
      const len = width * height;
      const px  = new Uint8ClampedArray(len * 4); // 書き込み先は常に px
      const hasND = Number.isFinite(nodata);

      // 1バンドのときは 0-255 に正規化（可視化のため）
      const band1 = bands.length === 1 ? bands[0] : null;
      let norm = null;
      if (band1) {
        let min=Infinity,max=-Infinity;
        for (let i=0;i<len;i++){ const v=band1[i]; if(Number.isFinite(v)){ if(v<min)min=v; if(v>max)max=v; } }
        const span = (max>min)? (255/(max-min)) : 1;
        norm = (v)=> Math.max(0, Math.min(255, Math.round((v-min)*span)));
        console.info(`GeoTIFF 1バンドの可視化: min=${min}, max=${max}`);
      }

      for (let i=0;i<len;i++){
        const p = i<<2;
        // --- NoData 判定を「全バンド NoData の時だけ透明」に変更（全面透明化の防止）
        if (hasND){
          let allNoData = true;
          for (let b=0;b<bands.length;b++){
            if (bands[b][i] !== nodata){ allNoData = false; break; }
          }
          if (allNoData){ px[p+3]=0; continue; }
        }
        if (bands.length===1){
          const g = norm ? norm(band1[i]) : (band1[i] & 0xff);
          px[p]=g; px[p+1]=g; px[p+2]=g; px[p+3]=255;
        }else{
          px[p]    = bands[0][i] & 0xff;
          px[p+1]  = bands[1][i] & 0xff;
          px[p+2]  = bands[2][i] & 0xff;
          px[p+3]  = 255;
        }
      }
      
      // Leaflet の ImageOverlay 用に BlobURL を作る
      const canvas = document.createElement('canvas');
      canvas.width = width; canvas.height = height;
      const ctx = canvas.getContext('2d');
      ctx.putImageData(new ImageData(px, width, height), 0, 0);
      const blob = await new Promise(res=> canvas.toBlob(res));
      const url = URL.createObjectURL(blob);
      return { url, width, height, bounds };
    }
  } else {
    // デフォルトの表示（テスト用）
    ctx.fillStyle = '#8bc34a';
    ctx.fillRect(0, 0, width, height);
  }
  
  // そのままキャンバスへ出力 → Blob URL（巨大 dataURL を避ける）
  // キャンバスへ配置（px を使う）
  // Get the image data from the canvas context for both cases
  const imageDataFromCanvas = ctx.getImageData(0, 0, width, height);
  const raw = new ImageData(imageDataFromCanvas.data, width, height);
  const tmp = document.createElement('canvas');
  tmp.width = width; tmp.height = height;
  const tctx = tmp.getContext('2d');
  tctx.putImageData(raw, 0, 0);                       // 正: raw(px)
  // ブラウザ/GPU の限界対策：最大辺 8192 に縮小（オリジナルが大きい場合）
  const MAX_EDGE = 8192;
  let finalCanvas = tmp;
  if (Math.max(width, height) > MAX_EDGE) {
    const scale = MAX_EDGE / Math.max(width, height);
    const c2 = document.createElement('canvas');
    c2.width = Math.round(width*scale);
    c2.height = Math.round(height*scale);
    c2.getContext('2d').drawImage(tmp, 0, 0, c2.width, c2.height);
    finalCanvas = c2;
  }
  const blob = await new Promise(res=>finalCanvas.toBlob(res, 'image/png', 0.92));
  const dataUrl = URL.createObjectURL(blob);
  
  // バウンディングボックスを緯度経度に変換
  const boundsLatLng = computeLatLngBounds(image);
  
  return { dataUrl, boundsLatLng };
}

// WebMercator(EPSG:3857) → WGS84緯度経度
const R = 6378137;
function mercToLonLat(x, y) {
  const lon = (x / R) * 180 / Math.PI;
  const lat = (2 * Math.atan(Math.exp(y / R)) - Math.PI / 2) * 180 / Math.PI;
  const maxLat = 85.05112878; // WebMercator の理論上限
  return [lon, Math.max(Math.min(lat, maxLat), -maxLat)];
}
function looksLike3857BBox([minX, minY, maxX, maxY]) {
  // 4326(度)なら |x|≤180, |y|≤90 程度。超えていれば 3857(m) と推定
  return Math.abs(minX) > 180 || Math.abs(maxX) > 180 || Math.abs(minY) > 90 || Math.abs(maxY) > 90;
}
function bboxToLatLngBounds(bbox, epsg) {
  let sw, ne;
  if (epsg === 3857 || (!epsg && looksLike3857BBox(bbox))) {
    const [w, s] = mercToLonLat(bbox[0], bbox[1]);
    const [e, n] = mercToLonLat(bbox[2], bbox[3]);
    sw = [s, w]; ne = [n, e];
  } else {
    // 既に度（EPSG:4326 相当）
    sw = [bbox[1], bbox[0]];
    ne = [bbox[3], bbox[2]];
  }
  return L.latLngBounds(sw, ne);
}

function computeLatLngBounds(image) {
  // まずは geotiff.js の getBoundingBox があれば使う
  let west, south, east, north;
  if (typeof image.getBoundingBox === 'function') {
    const bb = image.getBoundingBox(); // [minX, minY, maxX, maxY]（多くは3857）
    [west, south, east, north] = bb;
  } else {
    // TiePoint + PixelScale から算出（yは画像下向きなので minus）
    const tie = image.getTiePoints()[0];
    const scale = image.getFileDirectory().ModelPixelScale;
    const w = image.getWidth(), h = image.getHeight();
    west  = tie.x;
    north = tie.y;
    east  = west  + w * scale[0];
    south = north - h * scale[1];
  }
  // SRS 判定（GeoKey で 3857 が来るケースを優先）
  let boundsLatLng;
  const gk = (typeof image.getGeoKeys==='function') ? image.getGeoKeys() : {};
  const is3857 = gk.ProjectedCSTypeGeoKey===3857 || gk.ProjectedCSTypeGeoKey===900913;
  if (is3857) {
    const sw = mercToLonLat(west, south);
    const ne = mercToLonLat(east, north);
    boundsLatLng = [[sw[1], sw[0]],[ne[1], ne[0]]];
  } else {
    // 既に経緯度（EPSG:4326）想定
    boundsLatLng = [[south, west],[north, east]];
  }
  
  return boundsLatLng;
}

/**
 * GeoTIFFファイルを読み込む関数（段階ログ付き）
 * @param {File} file - 読み込むGeoTIFFファイル
 * @returns {Promise<Object>} GeoTIFFイメージデータ
 */
export async function loadGeoTIFFWithSteps(file) {
  try {
    return await step(`File selected: ${file.name} (${file.size} bytes)`, async () => {
      const buf = await step('Read as ArrayBuffer', () => file.arrayBuffer());
      const tiff = await step('geotiff.fromArrayBuffer', () => fromArrayBuffer(buf));
      const image = await step('tiff.getImage(0)', () => tiff.getImage(0));
      
      const bbox = await step('image.getBoundingBox', () => image.getBoundingBox());
      // GeoKey から EPSG を取得（無い場合は数値スケールから自動推定）
      const geoKeys = (image.getGeoKeys && image.getGeoKeys()) || {};
      const epsg =
        geoKeys.ProjectedCSTypeGeoKey ||  // 例: 3857
        geoKeys.GeographicTypeGeoKey ||   // 例: 4326
        undefined;                        // 不明→推定

      const width  = image.getWidth();
      const height = image.getHeight();
      const keys = image.getGeoKeys?.() || {};
      const epsgCode = keys.ProjectedCSTypeGeoKey || keys.GeographicTypeGeoKey || 'unknown';
      report({phase:'image-meta', width, height, bbox, epsg: epsgCode});

      // 4326/3857 以外なら注意を出す（描画失敗の典型原因）
      if (![4326, 3857].includes(Number(epsgCode))) {
        report(raise(ERR.GEO_RENDER, '想定外の座標系の可能性', { epsg: epsgCode }), 'warn');
      }

      // 3857→4326 変換を挟んで Leaflet Bounds を作成
      const bounds = bboxToLatLngBounds(bbox, epsg);
      
      // ここで地図へ反映（最低限の動作例：範囲へズーム）
      // 実際のラスタ表示処理（既存の描画関数）も step() で包むと特定が速い
      const { url } = await step('Render raster overlay', async () => {
        // 既存の処理を使用
        return await loadGeoTIFFFromFileData(buf);
      });
      
      // URL と正しい bounds を返す（呼び出し側で地図へ追加）
      return { url, bounds };
    });
  } catch (e) {
    report(raise(ERR.GEO_PARSE, 'GeoTIFF 読み込みに失敗', { file: file.name }, e));
    throw e;
  }
}

/**
 * ファイルデータからGeoTIFFを読み込むヘルパー関数
 * @param {ArrayBuffer} buf - ファイルのArrayBuffer
 * @returns {Promise<Object>} GeoTIFFイメージデータ
 */
async function loadGeoTIFFFromFileData(buf) {
  // 既存のloadGeoTIFF関数を再利用
  return await loadGeoTIFF(buf);
}